import 'package:flutter/material.dart';
import 'package:flutter_payments/flutter_payments.dart';

class PaymentModule extends StatefulWidget {
  @override
  _PaymentModuleState createState() => _PaymentModuleState();
}

class _PaymentModuleState extends State<PaymentModule> {
  final FlutterPayments payments = FlutterPayments();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: ElevatedButton(
          onPressed: () async {
            // Set up the payment options
            final List<PaymentOption> options = [
              PaymentOption(id: 'apple_pay', displayName: 'Apple Pay'),
              PaymentOption(id: 'google_pay', displayName: 'Google Pay'),
              PaymentOption(id: 'samsung_pay', displayName: 'Samsung Pay'),
            ];

            // Prompt the user to select a payment option
            final selectedOption = await showModalBottomSheet(
              context: context,
              builder: (BuildContext context) {
                return ListView.builder(
                  itemCount: options.length,
                  itemBuilder: (BuildContext context, int index) {
                    final option = options[index];
                    return ListTile(
                      title: Text(option.displayName),
                      onTap: () => Navigator.of(context).pop(option),
                    );
                  },
                );
              },
            );

            // Send the payment request to the selected payment option
            final response = await payments.sendPaymentRequest(
              selectedOption.id,
              amount: 10.99,
              currencyCode: 'USD',
              billingAddressRequired: true,
            );

            // Handle the response from the payment gateway
            if (response != null && response.paymentSuccessful) {
              ScaffoldMessenger.of(context).showSnackBar(
                SnackBar(content: Text('Payment successful')),
              );
            } else {
              ScaffoldMessenger.of(context).showSnackBar(
                SnackBar(content: Text('Payment failed')),
              );
            }
          },
          child: Text('Pay'),
        ),
      ),
    );
